1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	  cursed?: boolean;
14	  enchantment?: number;
15	}
16	
17	const CURSE_RATE = 0.5;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_RATE = 0.3;
20	const LOYALTY_THRESHOLD = 2;
21	const LOYALTY_RATE = 0.2;
22	const FOLLOWUP_RATE = 0.15;
23	
24	interface QuoteStep {
25	  op: "quote";
26	  items: Item[];
27	}
28	
29	interface Damage {
30	  itemType: string;
31	  amount: number;
32	}
33	
34	interface ClaimStep {
35	  op: "claim";
36	  policy: number;
37	  incident: { cause: string; damages: Damage[] };
38	}
39	
40	type Step = QuoteStep | ClaimStep;
41	
42	interface Customer {
43	  yearsWithMHPCO: number;
44	}
45	
46	interface Scenario {
47	  customer: Customer;
48	  steps: Step[];
49	}
50	
51	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
52	const COMPONENT_BASE = 25;
53	const BLOCK_SIZE = 3;
54	const BLOCK_BASE = 60;
55	
56	const componentBase = (count: number): number =>
57	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
58	
59	const lookupByType = (
60	  type: string,
61	  componentValue: number,
62	  mainItemValues: Record<string, number>,
63	): number =>
64	  COMPONENT_TYPES.has(type) ? componentValue : (mainItemValues[type] ?? 0);
65	
66	const unitBase = (type: string): number =>
67	  lookupByType(type, COMPONENT_BASE, BASE_PREMIUMS);
68	
69	const baseForType = (type: string, count: number): number =>
70	  COMPONENT_TYPES.has(type)
71	    ? componentBase(count)
72	    : unitBase(type) * count;
73	
74	const countBy = <T>(values: T[], key: (value: T) => string): Map<string, number> =>
75	  values.reduce((counts, value) => {
76	    const group = key(value);
77	    return counts.set(group, (counts.get(group) ?? 0) + 1);
78	  }, new Map<string, number>());
79	
80	const countByType = (items: Item[]): Map<string, number> =>
81	  countBy(items, (item) => item.type);
82	
83	const baseForItems = (items: Item[]): number =>
84	  [...countByType(items)].reduce(
85	    (total, [type, count]) => total + baseForType(type, count),
86	    0,
87	  );
88	
89	const enchantmentLevel = (item: Item | undefined): number =>
90	  item?.enchantment ?? 0;
91	
92	const isHighlyEnchanted = (item: Item): boolean =>
93	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
94	
95	const surchargeRate = (item: Item): number =>
96	  (item.cursed ? CURSE_RATE : 0) +
97	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
98	
99	const itemSurcharges = (item: Item): number =>
100	  unitBase(item.type) * surchargeRate(item);
101	
102	const surchargesForItems = (items: Item[]): number =>
103	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
104	
105	const firstInsuranceSurcharge = (policyBase: number): number =>
106	  policyBase * FIRST_INSURANCE_RATE;
107	
108	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
109	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
110	
111	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
112	  isFollowUp ? policyBase * FOLLOWUP_RATE : 0;
113	
114	const isKnownType = (type: string): boolean =>
115	  COMPONENT_TYPES.has(type) || type in BASE_PREMIUMS;
116	
117	const validateKnownTypes = (items: Item[]): void => {
118	  const unknown = items.find((item) => !isKnownType(item.type));
119	  if (unknown) {
120	    throw new Error(`Unknown item type: ${unknown.type}`);
121	  }
122	};
123	
124	const priceQuote = (
125	  items: Item[],
126	  customer: Customer,
127	  isFollowUp: boolean,
128	): { premium: number } => {
129	  validateKnownTypes(items);
130	  const policyBase = baseForItems(items);
131	  const surcharges = surchargesForItems(items);
132	  const premium = Math.ceil(
133	    policyBase +
134	      surcharges +
135	      firstInsuranceSurcharge(policyBase) -
136	      loyaltyDiscount(policyBase, customer) -
137	      followUpDiscount(policyBase, isFollowUp) +
138	      PROCESSING_FEE,
139	  );
140	  return { premium };
141	};
142	
143	const DEDUCTIBLE = 100;
144	const CAP_MULTIPLIER = 2;
145	const HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD = 8;
146	const REIMBURSE_RATE = 0.5;
147	
148	const INSURANCE_VALUES: Record<string, number> = {
149	  sword: 1000,
150	  amulet: 600,
151	  staff: 800,
152	  potion: 400,
153	};
154	const COMPONENT_INSURANCE_VALUE = 250;
155	
156	const insuranceValue = (type: string): number =>
157	  lookupByType(type, COMPONENT_INSURANCE_VALUE, INSURANCE_VALUES);
158	
159	const insuranceSum = (items: Item[]): number =>
160	  items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
161	
162	const hasReducedReimbursement = (item: Item | undefined): boolean =>
163	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_REIMBURSE_THRESHOLD;
164	
165	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
166	  hasReducedReimbursement(item)
167	    ? damage.amount * REIMBURSE_RATE
168	    : damage.amount;
169	
170	const damagePayout = (damage: Damage, items: Item[]): number => {
171	  const item = items.find((candidate) => candidate.type === damage.itemType);
172	  return Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
173	};
174	
175	const initialCap = (items: Item[]): number =>
176	  insuranceSum(items) * CAP_MULTIPLIER;
177	
178	const desiredPayout = (damages: Damage[], items: Item[]): number =>
179	  damages.reduce((sum, damage) => sum + damagePayout(damage, items), 0);
180	
181	const validateDamageAmounts = (damages: Damage[]): void => {
182	  const negative = damages.find((damage) => damage.amount < 0);
183	  if (negative) {
184	    throw new Error(`Claim rejected: negative damage amount ${negative.amount}`);
185	  }
186	};
187	
188	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
189	  const insuredCounts = countByType(items);
190	  const damageCounts = countBy(damages, (damage) => damage.itemType);
191	  for (const [itemType, damaged] of damageCounts) {
192	    if (damaged > (insuredCounts.get(itemType) ?? 0)) {
193	      throw new Error(
194	        `Claim rejected: more "${itemType}" damages than insured items`,
195	      );
196	    }
197	  }
198	};
199	
200	const validateClaim = (damages: Damage[], items: Item[]): void => {
201	  validateDamageAmounts(damages);
202	  validateDamageCounts(damages, items);
203	};
204	
205	const processClaim = (
206	  step: ClaimStep,
207	  steps: Step[],
208	  remainingCapByPolicy: Map<number, number>,
209	): { payout: number; remainingCap: number } => {
210	  const policyStep = steps[step.policy] as QuoteStep;
211	  validateClaim(step.incident.damages, policyStep.items);
212	  const remaining =
213	    remainingCapByPolicy.get(step.policy) ?? initialCap(policyStep.items);
214	  const desired = desiredPayout(step.incident.damages, policyStep.items);
215	  const payout = Math.floor(Math.min(desired, remaining));
216	  const remainingCap = remaining - payout;
217	  remainingCapByPolicy.set(step.policy, remainingCap);
218	  return { payout, remainingCap };
219	};
220	
221	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
222	  const remainingCapByPolicy = new Map<number, number>();
223	  let quotesSoFar = 0;
224	  const results = scenario.steps.map((step) => {
225	    if (step.op === "quote") {
226	      const result = priceQuote(step.items, scenario.customer, quotesSoFar > 0);
227	      quotesSoFar += 1;
228	      return result;
229	    }
230	    return processClaim(step, scenario.steps, remainingCapByPolicy);
231	  });
232	  return { results };
233	};
