export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const remainingCapByPolicy = new Map<number, number>();
  let quotesSoFar = 0;
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const result = priceQuote(step.items, scenario.customer, quotesSoFar > 0);
      quotesSoFar += 1;
      return result;
    }
    return processClaim(step, scenario.steps, remainingCapByPolicy);
  });
  return { results };
};

